sql:
SELECT COUNT(*) 
FROM alerts_history
WHERE alert_id = 1 AND status = 'active';

SELECT transaction_id 
FROM transactions 
WHERE transaction_id NOT IN (SELECT transaction_id FROM liquidity_metrics);

SELECT AVG(processing_time) AS avg_processing_time, AVG(success_rate) AS avg_success_rate
FROM performance_metrics
WHERE retries > 2;

SELECT * 
FROM transactions 
WHERE amount > (
  SELECT AVG(amount) 
  FROM transactions
);

SELECT transactions.transaction_id, blocks.block_size
FROM transactions
JOIN blocks ON transactions.block_number = blocks.block_number;

SELECT transaction_id 
FROM transaction_indexes 
WHERE index_type = 'price' AND CAST(index_value AS REAL) > 100;

SELECT transaction_id
FROM liquidity_metrics
WHERE liquidity_rate > 5.0;

SELECT block_number, transaction_id
FROM transactions
WHERE transaction_id = 123;

SELECT *
FROM transactions
WHERE fee > 0.1 AND status = 'confirmed';

external_knowledge:
Recent transactions refer to those recorded within the last 24 hours;
Alerts are categorized by their severity level ('low', 'medium', 'high');
The resolution status is determined by whether there is a history entry for the alert, indicating 'Resolved' if present and 'Not Resolved' if absent.
